const chatId = String($env.OMX_NOTIFY_CHAT_ID || $env.TELEGRAM_CHAT_ID || '').trim();
const omxBaseUrl = String($env.OMX_NOTIFY_N8N_BASE_URL || 'https://n8n.pressco21.com').trim().replace(/\/$/, '');
const omxAppUrl = String($env.OMX_NOTIFY_APP_URL || 'https://mini.pressco21.com/omx').trim();
const sharedKey = String($env.OMX_SHARED_KEY || $env.OMX_SOURCE_KEY || '').trim();
const includeReviews = String($env.OMX_NOTIFY_INCLUDE_MAKESHOP_REVIEWS || 'true').trim().toLowerCase() !== 'false';
const maxLines = Number.parseInt(String($env.OMX_NOTIFY_MAX_LINES || '8').trim(), 10) || 8;
const initialSeedQuiet = String($env.OMX_NOTIFY_INITIAL_SEED_QUIET || 'true').trim().toLowerCase() !== 'false';
if (!sharedKey) {
  throw new Error('OMX_SHARED_KEY 가 설정되지 않았습니다.');
}
if (!chatId) {
  throw new Error('OMX_NOTIFY_CHAT_ID 또는 TELEGRAM_CHAT_ID 가 설정되지 않았습니다.');
}
return [{
  json: {
    chatId,
    omxBaseUrl,
    omxAppUrl,
    sharedKey,
    includeReviews,
    maxLines,
    initialSeedQuiet,
  }
}];

const config = $('실행 설정').first().json;
const smartstorePayload = $('스마트스토어 문의 가져오기').first().json || {};
const makeshopPayload = $('메이크샵 문의/리뷰 가져오기').first().json || {};
function extractItems(payload) {
  return Array.isArray(payload.items) ? payload.items : [];
}
const smartstoreItems = extractItems(smartstorePayload);
const makeshopItems = extractItems(makeshopPayload);
let combined = [...smartstoreItems, ...makeshopItems].filter((item) => item && item.id);
if (!config.includeReviews) {
  combined = combined.filter((item) => item.itemType !== 'review');
}
combined = combined.filter((item) => {
  const status = String(item.status || item.externalStatus || '').toUpperCase();
  return !['ANSWERED', 'SENT', 'CLOSED', 'DONE'].includes(status);
});
combined.sort((a, b) => new Date(a.receivedAt || 0).getTime() - new Date(b.receivedAt || 0).getTime());
const workflowState = $getWorkflowStaticData('global');
const seen = workflowState.omxSeen || {};
const nowIso = new Date().toISOString();
const cutoffMs = Date.now() - 45 * 24 * 60 * 60 * 1000;
for (const [key, value] of Object.entries(seen)) {
  const stored = value && typeof value === 'object' ? value : {};
  const at = new Date(stored.firstSeenAt || stored.lastSeenAt || 0).getTime();
  if (!Number.isFinite(at) || at < cutoffMs) {
    delete seen[key];
  }
}
const newItems = [];
for (const item of combined) {
  const key = `${item.channel || 'unknown'}:${item.itemType || 'inquiry'}:${item.id}`;
  if (!seen[key]) {
    newItems.push(item);
    seen[key] = {
      firstSeenAt: nowIso,
      lastSeenAt: nowIso,
      title: String(item.title || ''),
      channel: String(item.channel || ''),
      itemType: String(item.itemType || 'inquiry'),
      receivedAt: String(item.receivedAt || ''),
    };
    continue;
  }
  seen[key].lastSeenAt = nowIso;
}
workflowState.omxSeen = seen;
const sourceCounts = {
  smartstore: smartstoreItems.length,
  makeshop: makeshopItems.length,
};
if (!workflowState.omxBaselineInitialized) {
  workflowState.omxBaselineInitialized = true;
  workflowState.omxBaselineAt = nowIso;
  return [{
    json: {
      shouldSend: config.initialSeedQuiet ? false : newItems.length > 0,
      seeded: true,
      seededCount: combined.length,
      newCount: newItems.length,
      newItems,
      sourceCounts,
      chatId: config.chatId,
      omxAppUrl: config.omxAppUrl,
      maxLines: config.maxLines,
      fetchedAt: nowIso,
    }
  }];
}
return [{
  json: {
    shouldSend: newItems.length > 0,
    seeded: false,
    seededCount: 0,
    newCount: newItems.length,
    newItems,
    sourceCounts,
    chatId: config.chatId,
    omxAppUrl: config.omxAppUrl,
    maxLines: config.maxLines,
    fetchedAt: nowIso,
  }
}];

const input = $input.first().json;
const items = Array.isArray(input.newItems) ? input.newItems : [];
const maxLines = Number(input.maxLines || 8) || 8;
const appUrl = String(input.omxAppUrl || 'https://mini.pressco21.com/omx').trim();
function truncate(text, length = 48) {
  const value = String(text || '').replace(/\s+/g, ' ').trim();
  if (!value) return '-';
  return value.length > length ? `${value.slice(0, length - 1)}…` : value;
}
function formatDate(value) {
  const date = new Date(value || Date.now());
  return new Intl.DateTimeFormat('ko-KR', {
    timeZone: 'Asia/Seoul',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).format(date);
}
function classify(item) {
  if (item.itemType === 'review') return '후기';
  const text = `${item.rawCategory || ''} ${item.subject || item.title || ''} ${item.body || ''}`;
  if (/(사업자|도매|대량견적|세금계산서)/.test(text)) return '사업자';
  if (/(불량|고장|파손|깨짐|문제|나사|불빛|점등)/.test(text)) return '불량';
  if (/(비율|사용법|경화|굳|혼합|처음)/.test(text)) return '사용법';
  if (/(재고|입고|품절|대량)/.test(text)) return '재고/입고';
  if (/(배송|출고|송장|언제)/.test(text)) return '배송';
  if (/(반품|교환|환불)/.test(text)) return '교환/반품';
  return '일반';
}
function attachmentCount(item) {
  if (Array.isArray(item.attachments)) return item.attachments.length;
  if (typeof item.attach === 'string' && item.attach.trim()) return item.attach.split(/[\n,]/).filter(Boolean).length;
  return 0;
}
let text = `📥 OMX 신규 응답건 ${items.length}건\n`;
text += `확인 시각: ${formatDate(input.fetchedAt)}\n`;
text += `소스: 스마트스토어 ${input.sourceCounts?.smartstore || 0} · 메이크샵 ${input.sourceCounts?.makeshop || 0}\n\n`;
items.slice(0, maxLines).forEach((item, index) => {
  const channelLabel = item.channelLabel || (item.channel === 'smartstore' ? '스마트스토어' : item.channel === 'makeshop' ? '메이크샵' : item.channel || '채널');
  const itemTypeLabel = item.itemType === 'review' ? '리뷰' : '문의';
  const category = classify(item);
  const attachments = attachmentCount(item);
  text += `${index + 1}. [${channelLabel} · ${itemTypeLabel} · ${category}]\n`;
  text += `고객: ${truncate(item.customerName || '고객', 20)}\n`;
  if (item.productName) {
    text += `상품: ${truncate(item.productName, 30)}\n`;
  }
  text += `제목: ${truncate(item.subject || item.title || '-', 36)}\n`;
  text += `내용: ${truncate(item.body || item.content || '-', 56)}\n`;
  if (attachments) {
    text += `첨부: ${attachments}건\n`;
  }
  text += `접수: ${formatDate(item.receivedAt)}\n\n`;
});
if (items.length > maxLines) {
  text += `외 ${items.length - maxLines}건 더 있음\n\n`;
}
text += `OMX 열기: ${appUrl}`;
return [{ json: { chatId: input.chatId, text } }];
